+/**
+ * Tests for Undo/Redo Manager
+ *
+ * @see brenner_bot-sedg (Undo/Redo System)
+ */
+
+import { describe, it, expect, beforeEach } from "vitest";
+import type { Session } from "./types";
+import {
+  createUndoStack,
+  createConfidenceCommand,
