+    timestamp: new Date().toISOString(),
+    description: `Set primary hypothesis`,
+    executeData: {
+      hypothesisId: newPrimaryId,
+      previousPrimaryId,
+    },
+    undoData: {
+      hypothesisId: previousPrimaryId,
+      previousPrimaryId: newPrimaryId,
+    },
+  };
