+    type: "archive_hypothesis",
+    timestamp: new Date().toISOString(),
+    description: `Archive hypothesis`,
+    executeData: {
+      hypothesisId,
+      reason,
+    },
+    undoData: {
+      hypothesisId,
+    },
+  };
