+    id: generateCommandId(),
+    type: "restore_hypothesis",
+    timestamp: new Date().toISOString(),
+    description: `Restore hypothesis from archive`,
+    executeData: {
+      hypothesisId,
+    },
+    undoData: {
+      hypothesisId,
+    },
+  };
